      "keystrokes": "cat > solution.sh << 'EOF'
#!/bin/bash

# Function to extract peaks using awk
extract_peaks() {
    awk -F',' '
    BEGIN {
        OFS = ","
        print "frame,f1_bin,f2_bin,f3_bin"
    }
    NR > 1 {
        # Skip header row
        frame = $1
        bin = $2
        val = $3

        # Store magnitude for each frame and bin
        mag[frame, bin] = val

        # Track bins for each frame
        if (!(frame in frames)) {
            frames[frame] = 1
            frame_list[++frame_count] = frame
        }
        if (!(frame in bin_counts)) {
            bin_counts[frame] = 0
        }
        bins[frame, ++bin_counts[frame]] = bin
    }
    END {
        # Process each frame
        for (i = 1; i <= frame_count; i++) {
            frame = frame_list[i]

            # Create array of bin,magnitude pairs for this frame
            delete frame_data
            for (j = 1; j <= bin_counts[frame]; j++) {
                bin = bins[frame, j]
                frame_data[j] = bin " " mag[frame, bin]
            }

            # Sort by magnitude (descending)
            n = bin_counts[frame]
            for (a = 1; a <= n; a++) {
                for (b = a + 1; b <= n; b++) {
                    split(frame_data[a], temp_a)
                    split(frame_data[b], temp_b)
                    if (temp_a[2] + 0 < temp_b[2] + 0) {
                        temp = frame_data[a]
                        frame_data[a] = frame_data[b]
                        frame_data[b] = temp
                    }
                }
            }

            # Extract top 3 bins
            split(frame_data[1], top1)
            split(frame_data[2], top2)
            split(frame_data[3], top3)

            print frame, top1[1], top2[1], top3[1]
        }
    }' data/mag.csv > data/peaks.csv
}

# Main pipeline
if [ "$PEAKS_ONLY" = "1" ]; then
    echo "PEAKS_ONLY mode: processing existing mag.csv"
    extract_peaks
else
    echo "Running full pipeline..."
    python3 audioproc.py
    echo "Extracting peaks with awk..."
    extract_peaks
fi

echo "Pipeline complete!"
EOF
